                get_response = panel.process_request
        self.process_request = get_response
        self._panels = {panel.panel_id: panel for panel in reversed(panels)}
        self.stats = {}
        self.server_timing_stats = {}
        self.request_id = request_id
        self.init_store()
        self._created.send(request, toolbar=self)

def _handle_pk_field(queryset):
    pk = queryset.model._meta.pk

    if isinstance(pk, ForeignKey):
        return _handle_pk_field(pk.target_field)

    if isinstance(pk, (
        IntegerField, AutoField, BigIntegerField,
        PositiveIntegerField, PositiveSmallIntegerField, SmallIntegerField,
    )):
        return partial(Cast, output_field=BigIntegerField())

    if isinstance(pk, UUIDField):
        if connection.features.has_native_uuid_field:
            return partial(Cast, output_field=UUIDField())
        return partial(
            Replace, text=Value("-"),
            replacement=Value(""),
            output_field=CharField(),
        )

    return None

def get_next_link(self):
    if not self.page.has_next():
        return None
    url = self.request.build_absolute_uri()
    page_number = self.page.next_page_number()
    return replace_query_param(url, self.page_query_param, page_number)


def get_previous_link(self):
    if not self.page.has_previous():
        return None
    url = self.request.build_absolute_uri()
    page_number = self.page.previous_page_number()
    if page_number == 1:
        return remove_query_param(url, self.page_query_param)
    return replace_query_param(url, self.page_query_param, page_number)

def get_next_link(self):
    if self.offset + self.limit >= self.count:
        return None

    url = self.request.build_absolute_uri()
    url = replace_query_param(url, self.limit_query_param, self.limit)

    offset = self.offset + self.limit
    return replace_query_param(url, self.offset_query_param, offset)


def get_previous_link(self):
    if self.offset <= 0:
        return None

    url = self.request.build_absolute_uri()
    url = replace_query_param(url, self.limit_query_param, self.limit)

    if self.offset - self.limit <= 0:
        return remove_query_param(url, self.offset_query_param)

    offset = self.offset - self.limit
    return replace_query_param(url, self.offset_query_param, offset)

def reauthenticate(self, user: AbstractBaseUser, password: str) -> bool:
        from allauth.account.models import EmailAddress
        from allauth.account.utils import user_username

        credentials = {"password": password}
        username = user_username(user)
        if username:
            credentials["username"] = username
        email = EmailAddress.objects.get_primary_email(user)
        if email:
            credentials["email"] = email
        if app_settings.LoginMethod.PHONE in app_settings.LOGIN_METHODS:
            phone_verified = self.get_phone(user)
            if phone_verified:
                credentials["phone"] = phone_verified[0]
        reauth_user = self.authenticate(context.request, **credentials)
        return reauth_user is not None and reauth_user.pk == user.pk

def get_login_redirect_url(
    request: HttpRequest,
    url=None,
    redirect_field_name=REDIRECT_FIELD_NAME,
    signup=False,
) -> str:
    ret = url
    if url and callable(url):
        # In order to be able to pass url getters around that depend
        # on e.g. the authenticated state.
        ret = url()
    if not ret:
        ret = get_next_redirect_url(request, redirect_field_name=redirect_field_name)
    if not ret:
        if signup:
            ret = get_adapter().get_signup_redirect_url(request)
        else:
            ret = get_adapter().get_login_redirect_url(request)
    return ret

def add_email(
        self,
        request: HttpRequest,
        user: AbstractBaseUser,
        email,
        confirm=False,
        signup=False,
    ) -> EmailAddress:
        from allauth.account.internal.flows.email_verification import (
            send_verification_email_to_address,
        )

        email = email.lower()
        email_address, created = self.get_or_create(
            user=user, email=email, defaults={"email": email}
        )

        if created and confirm:
            send_verification_email_to_address(request, email_address)

        return email_address

def get_for_user(self, user: AbstractBaseUser, email) -> EmailAddress:
        cache_key = "_emailaddress_cache"
        addresses = getattr(user, cache_key, None)
        email = email.lower()
        if addresses is None:
            ret = self.get(user_id=user.pk, email=email.lower())
            # To avoid additional lookups when e.g.
            # EmailAddress.set_as_primary() starts touching self.user
            ret.user = user  # type:ignore[assignment]
            return ret
        else:
            for address in addresses:
                if address.email == email:
                    return address
            raise self.model.DoesNotExist()

